// KnowledgeCategories.jsx
import React, { useState, useEffect } from 'react';
import { QA_CATEGORIES, QA_ARTICLES } from '../components/data/qa-data';
import CategoryCard from './CategoryCard';
import ArticleModal from './ArticleModal';
import '../KnowledgeCategories.css';

const KnowledgeCategories = () => {
    const [selectedCategory, setSelectedCategory] = useState(null);
    const [selectedArticle, setSelectedArticle] = useState(null);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [categoryArticles, setCategoryArticles] = useState([]);
    console.log('QA_CATEGORIES:', QA_CATEGORIES);
    console.log('QA_ARTICLES:', QA_ARTICLES);
    console.log('QA_ARTICLES length:', QA_ARTICLES?.length);

    useEffect(() => {
        const handleOpenCategoryModal = (e) => {
            const cat = e.detail;
            handleCategoryClick(cat);
        };
        window.addEventListener('openCategoryModal', handleOpenCategoryModal);
        return () => window.removeEventListener('openCategoryModal', handleOpenCategoryModal);
    }, []);

    // Category icons mapping
    const CATEGORY_ICONS = {
        'SAFE': '📄',
        'Convertible Debt': '💵',
        'Preferred Equity': '⭐',
        'Common Equity': '📊',
        'Warrants': '📜',
        'Instrument Comparisons': '⚖️',
        'Investor Reporting': '📈',
        'Data Room & Due Diligence': '📁',
        'Dilution & Ownership Modeling': '🧮',
        'Fundraising Rounds & Process': '🚀',
        'Valuation Fundamentals': '💎',
        'Vesting & Equity Compensation': '⏳',
        'Governance & Shareholder Rights': '🏛️',
        'M&A, Exits & Liquidity': '🤝',
        'Angel Investing Fundamentals': '👼',
        'Founder-Investor Relationships': '💞',
        'Term Sheet Structure and Fundamentals': '📋'
    };

    // Category display names mapping
    const CATEGORY_DISPLAY = {
        'SAFE': 'SAFE',
        'Convertible Debt': 'Convertible Debt',
        'Preferred Equity': 'Preferred Equity',
        'Common Equity': 'Common Equity',
        'Warrants': 'Warrants',
        'Instrument Comparisons': 'Instrument Comparisons',
        'Investor Reporting': 'Investor Reporting',
        'Data Room & Due Diligence': 'Data Room & Due Diligence',
        'Dilution & Ownership Modeling': 'Dilution',
        'Fundraising Rounds & Process': 'Fundraising',
        'Valuation Fundamentals': 'Valuation',
        'Vesting & Equity Compensation': 'Vesting',
        'Governance & Shareholder Rights': 'Governance',
        'M&A, Exits & Liquidity': 'M&A & Exit',
        'Angel Investing Fundamentals': 'Angel Investing',
        'Founder-Investor Relationships': 'Founder-Investor Relationships',
        'Term Sheet Structure and Fundamentals': 'Term Sheets'
    };

    // Get the first article for a category (or you can show all articles in modal)
    const getCategoryArticle = (categoryName) => {
        const articles = QA_ARTICLES.filter(article => article.category === categoryName);
        return articles.length > 0 ? articles[0] : null;
    };

    // Get all articles for a category
    const getCategoryArticles = (categoryName) => {
        return QA_ARTICLES.filter(article => article.category === categoryName);
    };

    const handleCategoryClick = (category) => {
        const articles = getCategoryArticles(category.name);
        if (articles.length > 0) {
            setSelectedCategory(category);
            setCategoryArticles(articles);
            setSelectedArticle(articles[0]); // Show first article by default
            setIsModalOpen(true);
        }
    };

    const handleCloseModal = () => {
        setIsModalOpen(false);
        setSelectedCategory(null);
        setSelectedArticle(null);
        setCategoryArticles([]);
    };

    const handleArticleSelect = (article) => {
        setSelectedArticle(article);
    };

    return (
        <>
         
                {QA_CATEGORIES.slice(0, 6).map((cat) => {
                    const firstArticle = getCategoryArticle(cat.name);
                    return (
                        <CategoryCard
                            key={cat.name}
                            icon={CATEGORY_ICONS[cat.name] || '📚'}
                            label={CATEGORY_DISPLAY[cat.name] || cat.name}
                            count={cat.count}
                            title={firstArticle ? firstArticle.question : 'Explore ' + cat.name}
                            preview={firstArticle ? firstArticle.answer.substring(0, 120) + '...' : ''}
                            onClick={() => handleCategoryClick(cat)}
                        />
                    );
                })}
          

            {selectedCategory && selectedArticle && (
                <ArticleModal
                    isOpen={isModalOpen}
                    onClose={handleCloseModal}
                    category={selectedCategory}
                    article={selectedArticle}
                    articles={categoryArticles}
                    onArticleSelect={handleArticleSelect}
                    icon={CATEGORY_ICONS[selectedCategory.name] || '📚'}
                />
            )}
       
           {/* <div className="knowledge-categories-container">
            <div className="knowledge-categories">
                {QA_CATEGORIES.map((cat) => {
                    const firstArticle = getCategoryArticle(cat.name);
                    return (
                        <CategoryCard
                            key={cat.name}
                            icon={CATEGORY_ICONS[cat.name] || '📚'}
                            label={CATEGORY_DISPLAY[cat.name] || cat.name}
                            count={cat.count}
                            title={firstArticle ? firstArticle.question : 'Explore ' + cat.name}
                            preview={firstArticle ? firstArticle.answer.substring(0, 120) + '...' : ''}
                            onClick={() => handleCategoryClick(cat)}
                        />
                    );
                })}
            </div>

            {selectedCategory && selectedArticle && (
                <ArticleModal
                    isOpen={isModalOpen}
                    onClose={handleCloseModal}
                    category={selectedCategory}
                    article={selectedArticle}
                    articles={categoryArticles}
                    onArticleSelect={handleArticleSelect}
                    icon={CATEGORY_ICONS[selectedCategory.name] || '📚'}
                />
            )}
        </div> */}
        </>
     
    );
};

export default KnowledgeCategories;